1	/** A live cell on the infinite grid, represented as an [x, y] coordinate tuple. */
2	export type LiveCell = [number, number];
3	
4	/** Computes the next generation of live cells per Conway's Game of Life rules. */
5	export function nextGeneration(liveCells: LiveCell[]): LiveCell[] {
6	  const key = (x: number, y: number) => `${x},${y}`;
7	  const liveCellKeys = new Set(liveCells.map(([x, y]) => key(x, y)));
8	  const countNeighbors = (x: number, y: number) => {
9	    let count = 0;
10	    for (let dx = -1; dx <= 1; dx++) {
11	      for (let dy = -1; dy <= 1; dy++) {
12	        if (dx === 0 && dy === 0) continue;
13	        if (liveCellKeys.has(key(x + dx, y + dy))) count++;
14	      }
15	    }
16	    return count;
17	  };
18	  const survives = (cell: LiveCell) => {
19	    const neighborCount = countNeighbors(cell[0], cell[1]);
20	    return neighborCount === 2 || neighborCount === 3;
21	  };
22	  return liveCells.filter(survives);
23	}
